customHandlers.biliListHandler:
function(ctx) {
    var fetchJson = function(url) { return JSON.parse(req(url).content); };
    var url = "https://api.bilibili.com/x/space/arc/search?mid=928123&ps=30&pn=1&order=pubdate";
    var json = fetchJson(url);
    if (json.code !== 0) return [];
    var vlist = json.data.list.vlist || [];
    var result = vlist.map(function(v) {
      return {
        vod_id: "###" + v.aid + "###" + v.title + "###" + v.pic,
        vod_name: v.title,
        vod_pic: v.pic
      };
    });

    return result;
  }

customHandlers.biliDetailHandler:
function(ctx) {
    var parts = ctx.vodId.split('###');
    if (parts.length < 3) return { list: [] };
    var aid = parts[1];
    var title = parts[2];
    var pic = parts[3] || "";
    var infoUrl = "https://api.bilibili.com/x/web-interface/view?aid=" + aid;
    var infoJson = JSON.parse(req(infoUrl).content);
    if (infoJson.code !== 0) return { list: [] };
    var pages = infoJson.data.pages || [];
    var playList = pages.map(function(p) {
      var playId = aid + "|" + p.cid;
      return (p.part || "第" + p.page + "集") + "$" + playId;
    });
    var result = {
      list: [{
        vod_id: ctx.vodId,
        vod_name: title,
        vod_pic: pic,
        type_name: infoJson.data.tname || "B站视频",
        vod_play_from: "B站",
        vod_play_url: playList.join("#")
      }]
    };

    return result;
  }

